<?php
namespace App\Console\Commands; use App\Models\User; use Illuminate\Console\Command;
class CreateAdministrator extends Command { protected $signature='admin:create {email?}'; protected $description='Create or update the initial administrator using a hidden password prompt'; public function handle():int{$email=$this->argument('email')?:$this->ask('Administrator email');$name=$this->ask('Administrator name','Administrator');$password=$this->secret('Password (minimum 8 characters)');if(strlen((string)$password)<8){$this->error('Password must contain at least 8 characters.');return self::FAILURE;}User::updateOrCreate(['email'=>$email],['name'=>$name,'password'=>$password,'role'=>'admin','is_active'=>true,'must_change_password'=>false]);$this->info('Administrator account is ready.');return self::SUCCESS;}}
